/// <summary>
/// Constructs the controller for the batch operation.
/// </summary>
public static AslXyzBatchController construct()
{
    AslXyzBatchController controller = new AslXyzBatchController();
    controller.parmClassName(classStr(AslXyzBatchService));
    controller.parmMethodName(methodStr(AslXyzBatchService, process));
    return controller;
}

/// <summary>
/// Entry point invoked from the menu item.
/// </summary>
public static void main(Args _args)
{
    AslXyzBatchController controller = AslXyzBatchController::construct();
    controller.parmDialogCaption(literalStr("@AslRent:XyzProcessBatch"));
    controller.startOperation();
}
